cat > /tmp/uno-repro-linux-picker-spaces.sh <<'EOF'
#!/usr/bin/env bash
root="${1:-/workspace/uno}"
work="$(mktemp -d)"
trap 'rm -rf "$work"' EXIT
mkdir -p "$work/dir with space"
printf 'hello uno picker\n' > "$work/dir with space/file with space.txt"
uri="file://$work/dir%20with%20space/file%20with%20space.txt"
cat > "$work/Repro.cs" <<'CS'
using System;
using System.IO;
var uri = new Uri(args[0]);
var absolutePath = uri.AbsolutePath;
var localPath = uri.LocalPath;
using (var stream = File.Open(absolutePath, FileMode.OpenOrCreate, FileAccess.ReadWrite, FileShare.ReadWrite))
{
    Console.WriteLine($"AbsolutePath={absolutePath}");
    Console.WriteLine($"AbsolutePathLength={stream.Length}");
}
using (var stream = File.Open(localPath, FileMode.OpenOrCreate, FileAccess.ReadWrite, FileShare.ReadWrite))
{
    Console.WriteLine($"LocalPath={localPath}");
    Console.WriteLine($"LocalPathLength={stream.Length}");
}
Console.WriteLine($"SourceUsesAbsolutePath={File.ReadAllText(Path.Combine(args[1], "src/Uno.UI.Runtime.Skia.X11/Storage/Pickers/LinuxFilePickerExtension.cs")).Contains(".AbsolutePath")}");
CS
if command -v csi >/dev/null 2>&1; then
  csi "$work/Repro.cs" "$uri" "$root"
else
  mkdir "$work/app"
  cat > "$work/app/repro.csproj" <<'XML'
<Project Sdk="Microsoft.NET.Sdk">
  <PropertyGroup>
    <OutputType>Exe</OutputType>
    <TargetFramework>net10.0</TargetFramework>
    <Nullable>enable</Nullable>
    <ImplicitUsings>enable</ImplicitUsings>
  </PropertyGroup>
</Project>
XML
  mv "$work/Repro.cs" "$work/app/Program.cs"
  dotnet run --project "$work/app/repro.csproj" --no-restore -- "$uri" "$root"
fi
EOF
chmod +x /tmp/uno-repro-linux-picker-spaces.sh
/tmp/uno-repro-linux-picker-spaces.sh /workspace/uno

