cat > "$work/Repro.cs" <<'CS'
using System;
using System.IO;

static void Probe(string label, string uriText)
{
    var uri = new Uri(uriText);
    var absolutePath = uri.AbsolutePath;
    var localPath = uri.LocalPath;
    Console.WriteLine($"[{label}]");
    Console.WriteLine($"AbsolutePath={absolutePath}");
    try
    {
        using var absoluteStream = File.Open(absolutePath, FileMode.OpenOrCreate, FileAccess.ReadWrite, FileShare.ReadWrite);
        Console.WriteLine($"AbsolutePathLength={absoluteStream.Length}");
    }
    catch (Exception ex)
    {
        Console.WriteLine($"AbsolutePathError={ex.GetType().Name}");
    }

    Console.WriteLine($"LocalPath={localPath}");
    using var localStream = File.Open(localPath, FileMode.OpenOrCreate, FileAccess.ReadWrite, FileShare.ReadWrite);
    Console.WriteLine($"LocalPathLength={localStream.Length}");
    if (localStream.Length == 0)
    {
        throw new InvalidOperationException($"LocalPath did not open the selected file for {label}.");
    }
}

Probe("plain", args[0]);
Probe("filename-space", args[1]);
Probe("literal-percent", args[2]);
Probe("literal-hash", args[3]);
Probe("directory-and-filename-space", args[4]);
