Console.WriteLine($"SourceUsesLocalPath={source.Contains(".LocalPath")}");
if (!source.Contains(".LocalPath") || source.Contains(".AbsolutePath"))
{
    throw new InvalidOperationException("LinuxFilePickerExtension should convert portal file URIs with Uri.LocalPath.");
}
CS
mkdir "$work/app"
cat > "$work/app/repro.csproj" <<'XML'
<Project Sdk="Microsoft.NET.Sdk">
