    <OutputType>Exe</OutputType>
    <TargetFramework>net10.0</TargetFramework>
    <Nullable>enable</Nullable>
    <ImplicitUsings>enable</ImplicitUsings>
  </PropertyGroup>
</Project>
XML
mv "$work/Repro.cs" "$work/app/Program.cs"
dotnet run --project "$work/app/repro.csproj" -- "$uri_plain" "$uri_file_name" "$uri_percent" "$uri_hash" "$uri_dir_name" "$root"
EOF
